#!/usr/bin/env bun
/**
 * Capture the benchmark numbers the docs cite, with provenance, into a single
 * JSON the docs render as tables + charts. This is what keeps the benchmark
 * page honest: every number on it comes from a real `measure()` run on a known
 * machine, regenerated by `bun run src/capture.ts`, never hand-typed.
 *
 *   bun run src/capture.ts            # writes ../apps/docs/lib/bench-results.json
 */
import { cpus } from "node:os";
import { resolve } from "node:path";
import { createContainer, defineContainer } from "@re-reduced/core";
import { measure } from "mitata";
import { createStore } from "zustand/vanilla";

const round = (ns: number) => Number(ns.toFixed(ns < 100 ? 1 : 0));
/** mitata `measure()` returns avg in nanoseconds. */
const ns = async (fn: () => void) => round((await measure(fn)).avg);

const mkFields = (n: number): Record<string, number> =>
  Object.fromEntries(Array.from({ length: n }, (_, i) => [`f${i}`, 0]));

let sink = 0;

// ── dispatch throughput (one-field container) ──
const rr = createContainer(
  defineContainer("c", {
    state: { count: 0 },
    actions: (on) => ({ inc: on((s) => ({ count: s.count + 1 })) }),
  }),
);
const zs = createStore<{ count: number; inc: () => void }>((set) => ({
  count: 0,
  inc: () => set((s) => ({ count: s.count + 1 })),
}));
type S = { count: number };
const reducer = (s: S, a: { type: "inc" }) =>
  a.type === "inc" ? { count: s.count + 1 } : s;
let plain: S = { count: 0 };

const throughput = [
  {
    label: "plain reducer",
    ns: await ns(() => {
      plain = reducer(plain, { type: "inc" });
      sink += plain.count;
    }),
  },
  {
    label: "re-reduced",
    ns: await ns(() => {
      rr.actions.inc();
      sink += rr.$state.count.peek();
    }),
  },
  {
    label: "zustand",
    ns: await ns(() => {
      zs.getState().inc();
      sink += zs.getState().count;
    }),
  },
];

// ── dispatch vs field count (bump one field in a container of N) ──
const FIELDS = [1, 4, 16, 64];
const scaling = [];
for (const n of FIELDS) {
  const c = createContainer(
    defineContainer(`c${n}`, {
      state: mkFields(n),
      actions: (on) => ({ inc: on((s) => ({ ...s, f0: s.f0 + 1 })) }),
    }),
  );
  const z = createStore<Record<string, number>>(() => mkFields(n));
  scaling.push({
    fields: n,
    reReduced: await ns(() => {
      c.actions.inc();
      sink += c.$state.f0.peek();
    }),
    zustand: await ns(() => {
      z.setState((s) => ({ f0: s.f0 + 1 }));
      sink += z.getState().f0;
    }),
  });
}

// ── derivation crossover (memoized cached read vs recompute each read) ──
const WORK = [1, 4, 16, 64, 256, 1024];
const derive = [];
for (const w of WORK) {
  const items = Array.from({ length: w }, (_, i) => i);
  const store = createContainer(
    defineContainer(`d${w}`, {
      state: { items },
      actions: (on) => ({ noop: on((s) => s) }),
      derive: ($) => ({ sum: () => $.items.value.reduce((a, b) => a + b, 0) }),
    }),
  );
  store.$derived.sum.peek(); // warm the cache
  derive.push({
    work: w,
    memoized: await ns(() => {
      sink += store.$derived.sum.peek();
    }),
    recompute: await ns(() => {
      sink += items.reduce((a, b) => a + b, 0);
    }),
  });
}

const pkg = (name: string) =>
  // biome-ignore lint/suspicious/noExplicitAny: reading a version field off package.json
  (require(`${name}/package.json`) as any).version as string;

const results = {
  provenance: {
    cpu: cpus()[0]?.model ?? "unknown",
    cores: cpus().length,
    runtime: `Bun ${Bun.version}`,
    os: `${process.platform} ${process.arch}`,
    date: new Date().toISOString().slice(0, 10),
    versions: {
      "@re-reduced/core": pkg("@re-reduced/core"),
      zustand: pkg("zustand"),
      mitata: pkg("mitata"),
    },
  },
  throughput,
  scaling,
  derive,
};

const outFile = resolve(
  import.meta.dirname,
  "../../apps/docs/lib/bench-results.json",
);
await Bun.write(outFile, `${JSON.stringify(results, null, 2)}\n`);
console.log(`Wrote ${outFile}`);
if (sink === -1) console.log(sink); // guard against dead-code elimination
